(function() {
    const $ = window.jQuery;
    const REGEX = /\[([^\]]+?)\.\s*Рефлексия\]\s*([\s\S]+?)$/;
    const REGEX_FULL = /\[([^\]]+?)\.\s*Рефлексия\]\s*[\s\S]+?$/g;
    const CSS_ID = 'reflexio-css';
    const CONTEXT_KEEP = 3;
    const WORD_DELAY = 0.12;
    const CSS = `.refl{margin:16px 0;max-width:420px}
.refl summary{list-style:none;cursor:pointer}
.refl summary::-webkit-details-marker{display:none}
.refl-sum{background:var(--SmartThemeBlurTintColor);padding:10px 16px;border-radius:6px;border:1px solid var(--SmartThemeBorderColor);position:relative;overflow:hidden}
.refl-header{display:flex;align-items:center;justify-content:space-between}
.refl-tag{font-family:inherit;font-size:0.55em;letter-spacing:2px;text-transform:uppercase;color:var(--SmartThemeQuoteColor)}
.refl-dots{font-family:inherit;font-size:0.5em;color:var(--SmartThemeQuoteColor);opacity:0.4;letter-spacing:1px;transition:opacity 0.4s}
.refl[open] .refl-dots{opacity:0}
.refl-body{position:relative;padding:10px 16px;border-radius:6px;border:1px solid var(--SmartThemeBorderColor);background:var(--SmartThemeBlurTintColor);overflow:hidden}
.refl-body::before{content:"";position:absolute;inset:0;background:url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");opacity:0.04;pointer-events:none;z-index:0}
.refl-inner{position:relative;z-index:1;padding-top:2px}
.refl-who{font-family:inherit;font-size:0.75em;color:var(--SmartThemeEmColor);margin-bottom:4px;font-style:italic}
.refl-text{font-family:inherit;font-size:0.85em;line-height:1.75;font-style:italic;color:var(--SmartThemeEmColor)}
.refl-w{opacity:0;display:inline;filter:blur(3px);transition:none}
.refl[open] .refl-w{animation:wordIn 0.35s ease forwards}
@keyframes wordIn{0%{opacity:0;filter:blur(3px)}100%{opacity:1;filter:blur(0)}}`;

    let TH = null;
    const originals = new Map();

    function esc(s) { return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

    function wrapWords(text) {
        const lines = text.split('\n');
        let wordIdx = 0;
        const result = [];
        for (let l = 0; l < lines.length; l++) {
            if (l > 0) result.push('<br>');
            const words = lines[l].split(/(\s+)/);
            for (let w = 0; w < words.length; w++) {
                if (!words[w]) continue;
                if (/^\s+$/.test(words[w])) {
                    result.push(words[w]);
                } else {
                    const d = (wordIdx * WORD_DELAY).toFixed(3);
                    result.push('<span class="refl-w" style="animation-delay:' + d + 's">' + esc(words[w]) + '</span>');
                    wordIdx++;
                }
            }
        }
        return result.join('');
    }

    function renderVisual(messageId) {
        if (!TH) return;
        const msgs = TH.getChatMessages(messageId);
        if (!msgs || !msgs.length || !msgs[0].message) return;
        if (msgs[0].is_user) return;
        const match = msgs[0].message.match(REGEX);
        if (!match) return;
        const charName = match[1].trim();
        const reflText = match[2].trim();
        const $mes = TH.retrieveDisplayedMessage(messageId);
        if (!$mes || !$mes.length) return;
        const $target = $mes.find('.mes_text').length ? $mes.find('.mes_text') : $mes;
        let html = $target.html();
        if (!html || html.indexOf('class="refl"') >= 0) return;
        const needles = [
            '[' + charName + '. Рефлексия]',
            '[' + charName + '.\u00a0Рефлексия]',
            '[' + charName + '.&nbsp;Рефлексия]',
        ];
        let idx = -1;
        for (const n of needles) { idx = html.indexOf(n); if (idx >= 0) break; }
        if (idx < 0) {
            const loose = html.match(new RegExp('\\[' + charName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '[\\s\\S]{0,5}Рефлексия\\]'));
            if (loose) idx = loose.index;
        }
        if (idx < 0) return;
        const wrappedText = wrapWords(reflText);
        const widget = '<details class="refl"><summary><div class="refl-sum"><div class="refl-header"><span class="refl-tag">рефлексия</span><span class="refl-dots">· · ·</span></div></div></summary><div class="refl-body"><div class="refl-inner"><div class="refl-who">' + esc(charName) + '</div><div class="refl-text">' + wrappedText + '</div></div></div></details>';
        html = html.slice(0, idx) + widget;
        $target.html(html);
    }

    function cleanupForContext() {
        if (!TH) return;
        const lastId = TH.getLastMessageId();
        if (lastId < 0) return;
        const msgs = TH.getChatMessages('0-' + lastId);
        if (!msgs) return;
        let reflCount = 0;
        for (let i = msgs.length - 1; i >= 0; i--) {
            if (!msgs[i].message || msgs[i].is_user) continue;
            if (REGEX.test(msgs[i].message)) reflCount++;
        }
        if (reflCount <= CONTEXT_KEEP) return;
        let seen = 0;
        for (let i = msgs.length - 1; i >= 0; i--) {
            if (!msgs[i].message || msgs[i].is_user) continue;
            if (!REGEX.test(msgs[i].message)) continue;
            seen++;
            if (seen > CONTEXT_KEEP) {
                const mid = msgs[i].message_id;
                originals.set(mid, msgs[i].message);
                const cleaned = msgs[i].message.replace(REGEX_FULL, '').trim();
                TH.setChatMessage(mid, cleaned);
            }
        }
    }

    function restoreMessages() {
        if (!TH || originals.size === 0) return;
        originals.forEach(function(original, mid) {
            TH.setChatMessage(mid, original);
        });
        originals.clear();
        const scan = function() { $('.mes').each(function() { const id = $(this).attr('mesid'); if (id) renderVisual(Number(id)); }); };
        setTimeout(scan, 300);
    }

    function initializeScript() {
        if (!window.TavernHelper || !window.tavern_events || typeof window.eventOn !== 'function') { setTimeout(initializeScript, 200); return; }
        TH = window.TavernHelper;
        const ev = window.tavern_events;
        if (!$('#' + CSS_ID).length) $('head').append('<style id="' + CSS_ID + '">' + CSS + '</style>');
        window.eventOn(ev.CHARACTER_MESSAGE_RENDERED, renderVisual);
        window.eventOn(ev.MESSAGE_EDITED, function(id) { setTimeout(function(){ renderVisual(id); }, 100); });
        window.eventOn(ev.MESSAGE_UPDATED, function(id) { setTimeout(function(){ renderVisual(id); }, 100); });
        window.eventOn(ev.MESSAGE_SWIPED, function(id) { setTimeout(function(){ renderVisual(id); }, 100); });
        window.eventOn(ev.GENERATION_AFTER_COMMANDS, function() { cleanupForContext(); });
        window.eventOn(ev.GENERATION_ENDED, restoreMessages);
        window.eventOn(ev.GENERATION_STOPPED, restoreMessages);
        if (ev.GENERATION_ERROR) window.eventOn(ev.GENERATION_ERROR, restoreMessages);
        const scan = function() { $('.mes').each(function() { const id = $(this).attr('mesid'); if (id) renderVisual(Number(id)); }); };
        scan();
        window.eventOn(ev.CHAT_CHANGED, function(){ originals.clear(); setTimeout(scan, 500); });
        if (ev.MORE_MESSAGES_LOADED) window.eventOn(ev.MORE_MESSAGES_LOADED, scan);
        console.log('[Reflexio] init OK');
    }
    $(document).ready(initializeScript);
})();
